    public static class AESEncryptionUtility {
        
        public static String encryptData(String plainText) throws Exception {
            SecureRandom secureRandom = new SecureRandom();
            byte[] iv = new byte[16];
            secureRandom.nextBytes(iv);
            IvParameterSpec ivSpec = new IvParameterSpec(iv);
            
            byte[] keyBytes = new byte[32];
            secureRandom.nextBytes(keyBytes);
            SecretKeySpec keySpec = new SecretKeySpec(keyBytes, "AES");
            
            Cipher cipher = Cipher.getInstance("AES/CBC/PKCS5Padding");
            cipher.init(Cipher.ENCRYPT_MODE, keySpec, ivSpec);
            
            byte[] encrypted = cipher.doFinal(plainText.getBytes("UTF-8"));
            
            byte[] combined = new byte[iv.length + keyBytes.length + encrypted.length];
            System.arraycopy(iv, 0, combined, 0, iv.length);
            System.arraycopy(keyBytes, 0, combined, iv.length, keyBytes.length);
            System.arraycopy(encrypted, 0, combined, iv.length + keyBytes.length, encrypted.length);
            
            return Base64.getEncoder().encodeToString(combined);
        }
        
        public static String decryptData(String encryptedText) throws Exception {
            byte[] combined = Base64.getDecoder().decode(encryptedText);
            
            byte[] iv = new byte[16];
            byte[] keyBytes = new byte[32];
            byte[] encrypted = new byte[combined.length - 48];
            
            System.arraycopy(combined, 0, iv, 0, 16);
            System.arraycopy(combined, 16, keyBytes, 0, 32);
            System.arraycopy(combined, 48, encrypted, 0, encrypted.length);
            
            IvParameterSpec ivSpec = new IvParameterSpec(iv);
            SecretKeySpec keySpec = new SecretKeySpec(keyBytes, "AES");
            
            Cipher cipher = Cipher.getInstance("AES/CBC/PKCS5Padding");
            cipher.init(Cipher.DECRYPT_MODE, keySpec, ivSpec);
            
            byte[] decrypted = cipher.doFinal(encrypted);
            return new String(decrypted, "UTF-8");
        }
    }

